code = """import json
from collections import defaultdict

reviews = var_call_TjZlGsYyfOKrNSrLDCMV2y8P
business_docs = var_call_lGvCk0FWAmI5E7ADwxt1yiGr

# build business_id -> description map
biz_map = {b.get('business_id'): b for b in business_docs}

# helper to extract categories from description
import re

def extract_cats(desc):
    if not desc:
        return []
    desc_lower = desc.lower()
    # common keywords to locate categories
    keywords = [
        'in the categories of', 'in the category of', 'in the categories', 'in the category',
        'offers a range of services in', 'offers a range of products and services in',
        'offers a diverse range of products and services in the categories of',
        'offers a diverse range of services in', 'offers a range of services including',
        'offers a delightful selection of', 'offers a delightful array of', 'in the category',
        'in the categories', 'in the category of', 'including', "in the category of '",
        'in the categories of'
    ]
    for kw in keywords:
        idx = desc_lower.find(kw)
        if idx != -1:
            start = idx + len(kw)
            snippet = desc[start:]
            # cut at period
            snippet = snippet.split('.', 1)[0]
            # remove leading punctuation/words
            snippet = re.sub(r"^[^A-Za-z0-9]+", '', snippet)
            # split by commas and ' and '
            parts = re.split(r',| and | & |\band\b', snippet)
            cats = []
            for p in parts:
                p = p.strip()
                # remove trailing words like 'making it ...' or 'making it a ...'
                p = re.split(r'making it|making this|making them|providing|provides|offering', p, flags=re.I)[0].strip()
                # drop empty
                if p:
                    # remove leading 'the' or 'a'
                    p = re.sub(r'^(the |a |an )', '', p, flags=re.I).strip()
                    # remove stray words like 'Food' alone? keep as is
                    cats.append(p)
            if cats:
                return cats
    # fallback: try to extract tail after last comma before period
    last_sentence = desc.split('.')[-2] if '.' in desc else desc
    parts = re.split(r',| and | & |\band\b', last_sentence)
    # take those parts that look like categories (contains capital letters or spaces)
    cats = [p.strip() for p in parts if p.strip()]
    return cats

# accumulate counts per category
cat_counts = defaultdict(int)
missing = []
for r in reviews:
    bref = r['business_ref']
    count = int(r['review_count'])
    # map to business_id
    bid = bref.replace('businessref_', 'businessid_')
    b = biz_map.get(bid)
    if not b:
        missing.append(bid)
        continue
    desc = b.get('description', '')
    cats = extract_cats(desc)
    if not cats:
        # as final fallback, use business name as single category
        cats = [b.get('name', 'Unknown')]
    for c in cats:
        cat_counts[c] += count

# prepare sorted top 5
sorted_cats = sorted(cat_counts.items(), key=lambda x: x[1], reverse=True)
top5 = sorted_cats[:5]

result = [{'category': c, 'total_reviews': v} for c, v in top5]

print('__RESULT__:')
print(json.dumps(result))"""

